#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int a, sum1=0, sum2=0;
        for(int i=1;i<=10;i++){
            scanf("%d", &a);
            if(i%2) sum1+=a; else sum2+=a;
        }
        if(sum1==sum2) printf("0\n");
        else if(sum1>sum2) printf("1\n");
        else printf("2\n");
    }
    return 0;
}

