#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        sum1 = sum2 = 0
        for i in range(1, 11):
            val = int(next(it))
            if i % 2:
                sum1 += val
            else:
                sum2 += val
        if sum1 == sum2:
            out.append('0')
        elif sum1 > sum2:
            out.append('1')
        else:
            out.append('2')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

